import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type PageType = 'dashboard' | 'users' | 'analytics' | 'chat' | 'settings';

export interface ChatMessage {
  id: string;
  role: 'user' | 'assistant';
  content: string;
}

export interface UserData {
  id: number;
  name: string;
  email: string;
  role: string;
  status: 'active' | 'inactive';
  lastLogin: string;
}

import React, { useState, useEffect, Suspense } from 'react';
import { Sidebar } from './components/Sidebar';
import { Header } from './components/Header';
import { Dashboard } from './components/Dashboard';
import { UserManagement } from './components/UserManagement';
import { Analytics } from './components/Analytics';
import { AIChat } from './components/AIChat';
import { Settings } from './components/Settings';
import { PageType } from './types';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<PageType>('dashboard');

  // Handle Hash Routing
  useEffect(() => {
    const handleHashChange = () => {
      const hash = window.location.hash.replace('#', '') as PageType;
      if (['dashboard', 'users', 'analytics', 'chat', 'settings'].includes(hash)) {
        setCurrentPage(hash);
      }
    };

    window.addEventListener('hashchange', handleHashChange);
    // Initial check
    if (window.location.hash) {
      handleHashChange();
    } else {
      window.location.hash = 'dashboard';
    }

    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  const renderContent = () => {
    switch (currentPage) {
      case 'dashboard': return <Dashboard />;
      case 'users': return <UserManagement />;
      case 'analytics': return <Analytics />;
      case 'chat': return <AIChat />;
      case 'settings': return <Settings />;
      default: return <Dashboard />;
    }
  };

  return (
    <div className="flex h-screen w-full bg-slate-50 overflow-hidden">
      {/* Fixed Sidebar - No motion to prevent distraction */}
      <Sidebar currentPage={currentPage} />

      <div className="flex flex-col flex-1 min-w-0">
        {/* Fixed Header */}
        <Header currentPage={currentPage} />

        {/* Content Area - Only this area changes, frame stays solid */}
        <main className="flex-1 overflow-y-auto relative scroll-smooth bg-white">
          <div className="max-w-7xl mx-auto p-8">
            <Suspense fallback={<div className="animate-pulse h-full w-full bg-slate-100 rounded-xl" />}>
              <div key={currentPage} className="animate-[fadeIn_0.15s_ease-out]">
                {renderContent()}
              </div>
            </Suspense>
          </div>
        </main>
      </div>

      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; }
          to { opacity: 1; }
        }
      `}</style>
    </div>
  );
};

export default App;

