      ];

      if (validPages.includes(hash)) {
        setIsTransitioning(true);
        setTimeout(() => {
          setCurrentPage(hash);
          setIsTransitioning(false);
          const mainElement = document.getElementById('main-content');
          if (mainElement) mainElement.scrollTop = 0;
        }, 120); // Faster transition for "sync" feel
      }
    };

    window.addEventListener('hashchange', handleHashChange);
    if (window.location.hash) {
      handleHashChange();
    } else {
      window.location.hash = 'dashboard';
    }

    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  const renderContent = () => {
    switch (currentPage) {
      case 'dashboard': return <Dashboard />;
      case 'ai-basic': return <PlaceholderView title="AI 기본설정" description="AI의 기본적인 페르소나와 동작 방식을 설정합니다." />;
      case 'ai-style': return <PlaceholderView title="대화 스타일 설정" description="사용자와의 대화 톤앤매너를 관리합니다." />;
      case 'ai-condition': return <PlaceholderView title="조건별 답변 설정" description="특정 상황이나 키워드에 따른 맞춤 답변을 정의합니다." />;
      case 'kb-register': return <PlaceholderView title="지식등록" description="AI가 학습할 새로운 문서를 업로드하거나 URL을 입력합니다." />;
      case 'kb-manage': return <PlaceholderView title="지식관리" description="등록된 지식베이스를 편집하고 정확도를 검토합니다." />;
      case 'kb-api': return <PlaceholderView title="API 연동" description="외부 데이터 소스와의 실시간 동기화를 설정합니다." />;
      case 'test-chat': return <PlaceholderView title="대화 테스트" description="실제 환경과 동일한 샌드박스에서 AI의 답변을 검증합니다." />;
      case 'install-guide': return <PlaceholderView title="설치 안내" description="웹사이트에 챗봇을 적용하기 위한 스크립트 가이드를 확인합니다." />;
      case 'chat-manage': return <PlaceholderView title="대화관리" description="사용자와 AI 사이에 오간 전체 대화 내역을 모니터링합니다." />;
      case 'security-center': return <PlaceholderView title="보안센터" description="데이터 보호 설정 및 접근 권한을 관리합니다." />;
      default: return <Dashboard />;
    }
  };

  return (
    <div className="flex h-screen w-full bg-[#f8fafc] overflow-hidden select-none">
      <Sidebar currentPage={currentPage} />

      <div className="flex flex-col flex-1 min-w-0 bg-white">
        <Header currentPage={currentPage} />

        {/* Progress Bar for Sync feel */}
        <div className="h-0.5 w-full bg-slate-50 overflow-hidden relative">
          <div 
            className={`absolute top-0 left-0 h-full bg-indigo-500 transition-all duration-300 ease-in-out ${
              isTransitioning ? 'w-1/3' : 'w-full opacity-0'
            }`}
          />
        </div>

        <main id="main-content" className="flex-1 overflow-y-auto relative bg-[#f8fafc]">
          <div className={`max-w-7xl mx-auto p-8 transition-opacity duration-100 ${
            isTransitioning ? 'opacity-0' : 'opacity-100'
          }`}>
            {renderContent()}
          </div>
        </main>
      </div>

      <style>{`
        main { scrollbar-gutter: stable; }
        * { -webkit-font-smoothing: antialiased; }
      `}</style>
    </div>
  );
};

