import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { Header } from './components/Header';
import { Dashboard } from './components/Dashboard';
import { PlaceholderView } from './components/PlaceholderView';
import { PageType } from './types';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<PageType>('dashboard');
  const [isTransitioning, setIsTransitioning] = useState(false);

  useEffect(() => {
    const handleHashChange = () => {
      const hash = window.location.hash.replace('#', '') as PageType;
      const validPages: PageType[] = [
        'dashboard', 'ai-basic', 'ai-style', 'ai-condition', 
        'kb-register', 'kb-manage', 'kb-api', 
        'test-chat', 'install-guide', 
        'chat-manage', 'security-center'
      ];

      if (validPages.includes(hash)) {
        setIsTransitioning(true);
        // Small delay to ensure clean state reset if needed
        setTimeout(() => {
          setCurrentPage(hash);
          setIsTransitioning(false);
          const mainElement = document.getElementById('main-content');
          if (mainElement) mainElement.scrollTop = 0;
        }, 80);
      }
    };

    window.addEventListener('hashchange', handleHashChange);
    if (window.location.hash) {
      handleHashChange();
    } else {
      window.location.hash = 'dashboard';
    }

    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  const renderContent = () => {
    switch (currentPage) {
      case 'dashboard': return <Dashboard />;
      case 'ai-basic': return <PlaceholderView title="AI 기본설정" description="AI의 핵심 페르소나 및 응답 로직을 설정합니다." />;
      case 'ai-style': return <PlaceholderView title="대화 스타일 설정" description="브랜드 톤앤매너에 맞는 대화 스타일을 정의합니다." />;
