          >
            {renderContent()}
          </div>
        </main>
      </div>

      <style>{`
        /* Global CSS reset for layout stability */
        html, body, #root { 
          margin: 0; 
          padding: 0; 
          height: 100%; 
          width: 100%; 
        }
        * { box-sizing: border-box; }
      `}</style>
    </div>
  );
};

