import React, { useState, useCallback } from 'react';
import { Sidebar } from './components/Sidebar';
import { Header } from './components/Header';
import { Dashboard } from './components/Dashboard';
import { PlaceholderView } from './components/PlaceholderView';
import { PageType } from './types';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<PageType>('dashboard');
  const [isTransitioning, setIsTransitioning] = useState(false);

  // 'pseudo-latency'를 최소화하기 위한 즉각적인 페이지 전환 핸들러
  const handlePageChange = useCallback((page: PageType) => {
    if (page === currentPage) return;

    // 시각적 피로도를 낮추기 위해 매우 짧은 페이드 아웃/인 효과만 부여
    setIsTransitioning(true);

    // 50ms의 아주 짧은 딜레이로 화면 깜빡임을 방지하면서도 즉각적인 반응성 제공
    setTimeout(() => {
      setCurrentPage(page);
      setIsTransitioning(false);

      // 레이아웃 안정성을 위해 스크롤 위치 초기화
      const mainContent = document.getElementById('main-scroll-view');
      if (mainContent) mainContent.scrollTop = 0;
    }, 50);
  }, [currentPage]);

  const renderContent = () => {
    switch (currentPage) {
      case 'dashboard': return <Dashboard />;
      case 'ai-basic': return <PlaceholderView title="AI 기본설정" description="챗봇의 핵심 페르소나와 초기 구동 파라미터를 관리합니다." />;
      case 'ai-style': return <PlaceholderView title="대화 스타일 설정" description="브랜드 목소리에 맞춘 대화 톤앤매너를 커스터마이징합니다." />;
      case 'ai-condition': return <PlaceholderView title="조건별 답변 설정" description="특정 상황이나 복합 키워드에 따른 정교한 응답 로직을 구성합니다." />;
      case 'kb-register': return <PlaceholderView title="지식등록" description="AI가 학습할 문서, 데이터 시트 및 URL 지식을 추가합니다." />;
      case 'kb-manage': return <PlaceholderView title="지식관리" description="이미 학습된 지식의 정합성을 검토하고 업데이트 상태를 관리합니다." />;
      case 'kb-api': return <PlaceholderView title="API 연동" description="실시간 정보 조회를 위한 외부 데이터 API를 연동합니다." />;
      case 'test-chat': return <PlaceholderView title="대화 테스트" description="업데이트된 지식과 설정이 반영된 실시간 시뮬레이션을 진행합니다." />;
      case 'install-guide': return <PlaceholderView title="설치 안내" description="서비스 적용을 위한 임베디드 스크립트 가이드를 제공합니다." />;
      case 'chat-manage': return <PlaceholderView title="대화관리" description="사용자와의 대화 이력을 상세 분석하고 피드백을 수집합니다." />;
      case 'security-center': return <PlaceholderView title="보안센터" description="시스템 접근 기록과 데이터 보안 설정을 점검합니다." />;
      default: return <Dashboard />;
    }
  };

  return (
    <div className="flex h-screen w-full bg-[#f8fafc] overflow-hidden antialiased">
      {/* 사이드바: 상태 기반 이동으로 iframe 내 브라우저 뒤로가기/이동 오류 방지 */}
      <Sidebar currentPage={currentPage} onNavigate={handlePageChange} />

      <div className="flex flex-col flex-1 min-w-0 bg-white shadow-[-4px_0_24px_rgba(0,0,0,0.02)]">
        <Header currentPage={currentPage} />

        {/* 상단 진행 표시줄: 동작 중임을 알리는 최소한의 힌트 */}
        <div className="h-[2px] w-full bg-slate-50 relative overflow-hidden shrink-0">
          <div 
            className={`absolute top-0 left-0 h-full bg-indigo-600 transition-all duration-150 ease-out ${
              isTransitioning ? 'w-full opacity-100' : 'w-0 opacity-0'
            }`}
          />
        </div>

        <main 
          id="main-scroll-view" 
          className="flex-1 overflow-y-auto relative bg-[#f8fafc] custom-scrollbar"
        >
          <div 
            id="page-content-transition-layer"
            className={`max-w-7xl mx-auto p-8 transition-opacity duration-75 ${
              isTransitioning ? 'opacity-0' : 'opacity-100'
            }`}
          >
            {renderContent()}
          </div>
        </main>
      </div>

      <style>{`
        html, body, #root { margin: 0; padding: 0; height: 100%; width: 100%; }
        * { box-sizing: border-box; -webkit-font-smoothing: antialiased; }
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
      `}</style>
    </div>
  );
};

