import React from 'react';

export type ToastType = 'success' | 'error' | 'info';

interface ToastProps {
  message: string;
  type: ToastType;
}

export const Toast: React.FC<ToastProps> = ({ message, type }) => {
  const getIcon = () => {
    switch (type) {
      case 'success':
        return (
          <div className="w-5 h-5 bg-emerald-500 rounded-full flex items-center justify-center text-white mr-3">
            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
            </svg>
          </div>
        );
      case 'error':
        return (
          <div className="w-5 h-5 bg-rose-500 rounded-full flex items-center justify-center text-white mr-3">
            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className={`flex items-center bg-white border border-slate-200 pl-3 pr-6 py-3 rounded-2xl shadow-2xl animate-in slide-in-from-bottom-4 duration-300`}>
      {getIcon()}
      <span className="text-[13px] font-bold text-slate-900">{message}</span>
    </div>
  );
};

