        <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center mr-3">
          <span className="text-white text-[10px] font-bold">FF</span>
        </div>
        <span className="text-slate-800 font-bold text-[13px] tracking-tight uppercase">Control Center</span>
      </div>

      <nav className="flex-1 px-3 py-6 overflow-y-auto space-y-1 custom-scrollbar">
        {navigation.map((group, idx) => {
          const isMainActive = group.id === currentPage;
          const hasActiveChild = group.items?.some(i => i.id === currentPage);
          const isGroupExpanded = isMainActive || hasActiveChild;

          return (
            <div key={idx} className="mb-2">
              {group.id ? (
                <button
                  onClick={() => onNavigate(group.id as PageType)}
                  className={`w-full flex items-center px-3 py-2.5 rounded-lg text-sm font-semibold transition-colors duration-75 text-left ${
                    isMainActive
                      ? 'bg-slate-900 text-white shadow-none'
                      : 'text-slate-600 hover:bg-slate-50 hover:text-slate-900'
                  }`}
                >
                  <span className={`mr-3 ${isMainActive ? 'text-white' : 'text-slate-400'}`}>
                    {group.icon}
                  </span>
                  {group.label}
                </button>
              ) : (
                <div 
                  className={`flex items-center px-3 py-2.5 text-sm font-semibold ${
                    isGroupExpanded ? 'text-slate-900' : 'text-slate-500'
                  }`}
                >
                  <span className={`mr-3 ${isGroupExpanded ? 'text-indigo-600' : 'text-slate-300'}`}>
                    {group.icon}
                  </span>
                  {group.label}
                </div>
              )}

              {group.items && (
                <div className="mt-1 ml-10 space-y-1">
                  {group.items.map((item) => (
                    <button
                      key={item.id}
                      onClick={() => onNavigate(item.id)}
                      className={`w-full block text-left px-3 py-2 text-[13px] rounded-md transition-colors duration-75 ${
                        currentPage === item.id
                          ? 'text-indigo-600 font-bold bg-indigo-50/30'
                          : 'text-slate-500 hover:text-slate-900 hover:bg-slate-50'
                      }`}
                    >
                      {item.label}
                    </button>
                  ))}
                </div>
              )}
            </div>
          );
        })}
      </nav>

      <div className="p-4 bg-slate-50/50 border-t border-slate-100">
        <div className="bg-white p-3 rounded-xl border border-slate-200">
          <div className="flex items-center justify-between mb-2">
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Network</span>
            <span className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest">Stable</span>
          </div>
          <div className="flex items-center space-x-1">
             <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full"></div>
             <span className="text-[11px] text-slate-500 font-medium">Node: Seoul-East-1</span>
