import React, { useState, useCallback } from 'react';
import { Sidebar } from './components/Sidebar';
import { Header } from './components/Header';
import { Dashboard } from './components/Dashboard';
import { UserManagement } from './components/UserManagement';
import { AIBasicSettings } from './components/AIBasicSettings';
import { PlaceholderView } from './components/PlaceholderView';
import { Toast, ToastType } from './components/Toast';
import { ToastTest } from './components/ToastTest';
import { PageType } from './types';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<PageType>('dashboard');
  const [toasts, setToasts] = useState<{id: string, message: string, type: ToastType}[]>([]);

  const showToast = useCallback((message: string, type: ToastType = 'success') => {
    const id = Math.random().toString(36).substring(2, 9);
    setToasts(prev => [...prev, { id, message, type }]);
    setTimeout(() => {
      setToasts(prev => prev.filter(t => t.id !== id));
    }, 3000);
  }, []);

  const handlePageChange = useCallback((page: PageType) => {
    if (page === currentPage) return;
    setCurrentPage(page);

    const mainContent = document.getElementById('main-scroll-view');
    if (mainContent) mainContent.scrollTop = 0;
  }, [currentPage]);

  const renderContent = () => {
    switch (currentPage) {
      case 'dashboard': return <Dashboard />;
      case 'chat-manage': return <UserManagement onNotify={showToast} />;
      case 'ai-basic': return <AIBasicSettings onNotify={showToast} />;
      case 'test-toast': return <ToastTest onNotify={showToast} />;
      case 'ai-style': return <PlaceholderView title="대화 스타일 설정" description="브랜드 목소리에 맞춘 대화 톤앤매너를 커스터마이징합니다." />;
      case 'ai-condition': return <PlaceholderView title="조건별 답변 설정" description="특정 상황이나 복합 키워드에 따른 정교한 응답 로직을 구성합니다." />;
      case 'kb-register': return <PlaceholderView title="지식등록" description="AI가 학습할 문서, 데이터 시트 및 URL 지식을 추가합니다." />;
      case 'kb-manage': return <PlaceholderView title="지식관리" description="이미 학습된 지식의 정합성을 검토하고 업데이트 상태를 관리합니다." />;
      case 'kb-api': return <PlaceholderView title="API 연동" description="실시간 정보 조회를 위한 외부 데이터 API를 연동합니다." />;
      case 'test-chat': return <PlaceholderView title="대화 테스트" description="업데이트된 지식과 설정이 반영된 실시간 시뮬레이션을 진행합니다." />;
      case 'install-guide': return <PlaceholderView title="설치 안내" description="서비스 적용을 위한 임베디드 스크립트 가이드를 제공합니다." />;
      case 'security-center': return <PlaceholderView title="보안센터" description="시스템 접근 기록과 데이터 보안 설정을 점검합니다." />;
      default: return <Dashboard />;
    }
  };

  return (
    <div className="flex h-screen w-full bg-[#f8fafc] overflow-hidden antialiased text-slate-900">
      <Sidebar currentPage={currentPage} onNavigate={handlePageChange} />

      <div className="flex flex-col flex-1 min-w-0 bg-white shadow-[-4px_0_24px_rgba(0,0,0,0.01)]">
        <Header currentPage={currentPage} />

        <main 
          id="main-scroll-view" 
          className="flex-1 overflow-y-auto relative bg-[#f8fafc] custom-scrollbar"
        >
          {/* 메뉴 이동 인터렉션을 최소화하기 위해 slide-in을 제거하고 순수 fade-in(200ms)만 적용 */}
          <div 
            key={currentPage} 
            className="max-w-7xl mx-auto p-8 animate-in fade-in duration-200 ease-out fill-mode-both"
          >
            {renderContent()}
          </div>
        </main>
      </div>

      <div className="fixed bottom-6 right-6 z-[100] flex flex-col gap-3 pointer-events-none">
        {toasts.map(toast => (
          <div key={toast.id} className="pointer-events-auto">
            <Toast message={toast.message} type={toast.type} />
          </div>
        ))}
      </div>

      <style>{`
        html, body, #root { margin: 0; padding: 0; height: 100%; width: 100%; }
        * { box-sizing: border-box; -webkit-font-smoothing: antialiased; }
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 10px; }

        button:active { transform: scale(0.98); transition: transform 0.1s ease; }
      `}</style>
    </div>
  );
};

export default App;

import React from 'react';

export type ToastType = 'success' | 'error' | 'info';

interface ToastProps {
  message: string;
  type: ToastType;
}

export const Toast: React.FC<ToastProps> = ({ message, type }) => {
  const getIcon = () => {
    switch (type) {
      case 'success':
        return (
          <div className="w-5 h-5 bg-emerald-500 rounded-full flex items-center justify-center text-white mr-3 shadow-sm shadow-emerald-200">
            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
            </svg>
          </div>
        );
      case 'error':
        return (
          <div className="w-5 h-5 bg-rose-500 rounded-full flex items-center justify-center text-white mr-3 shadow-sm shadow-rose-200">
            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </div>
        );
      case 'info':
        return (
          <div className="w-5 h-5 bg-indigo-500 rounded-full flex items-center justify-center text-white mr-3 shadow-sm shadow-indigo-200">
            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className={`
      flex items-center bg-slate-900 text-white pl-3 pr-6 py-3.5 rounded-2xl 
      shadow-[0_20px_25px_-5px_rgba(0,0,0,0.2),0_10px_10px_-5px_rgba(0,0,0,0.1)]
      border border-white/10
      animate-in fade-in slide-in-from-bottom-5 duration-500 cubic-bezier(0.16, 1, 0.3, 1)
    `}>
      {getIcon()}
      <span className="text-[13px] font-bold tracking-tight">{message}</span>
    </div>
  );
};

