import React, { useState, useEffect } from 'react';

interface OnboardingProps {
  onComplete: () => void;
}

interface Step {
  targetId?: string;
  title: string;
  description: string;
  position: 'right' | 'left' | 'bottom' | 'top' | 'center';
  selector?: string; // CSS 셀렉터를 통한 위치 추적
}

const steps: Step[] = [
  {
    title: "Focus-Flow 가이드",
    description: "새롭게 바뀐 관리 시스템의 주요 기능을 직접 체험하며 확인해보세요.",
    position: 'center'
  },
  {
    title: "실시간 대시보드",
    description: "시스템의 핵심 지표를 한눈에 모니터링할 수 있는 영역입니다.",
    position: 'bottom',
    selector: '[data-tour="stats-grid"]'
  },
  {
    title: "AI 에이전트 설정",
    description: "브랜드만의 특별한 AI를 여기서 직접 커스터마이징 하세요.",
    position: 'right',
    selector: '[data-tour="nav-ai-settings"]'
  },
  {
    title: "스마트 관리 도구",
    description: "대화 로그 분석과 지식 관리를 통해 지능을 높일 수 있습니다.",
    position: 'right',
    selector: '[data-tour="nav-kb"]'
  }
];

export const Onboarding: React.FC<OnboardingProps> = ({ onComplete }) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [highlightRect, setHighlightRect] = useState<DOMRect | null>(null);

  useEffect(() => {
    const selector = steps[currentStep].selector;
    if (selector) {
      const el = document.querySelector(selector);
      if (el) {
        setHighlightRect(el.getBoundingClientRect());
      }
    } else {
      setHighlightRect(null);
    }
  }, [currentStep]);

  const handleNext = () => {
    if (currentStep < steps.length - 1) {
      setCurrentStep(currentStep + 1);
    } else {
      onComplete();
    }
  };

  const step = steps[currentStep];

  // 하이라이트 오버레이 스타일 (Spotlight 효과)
  const overlayStyle: React.CSSProperties = highlightRect ? {
    clipPath: `polygon(
      0% 0%, 0% 100%, 
      ${highlightRect.left}px 100%, 
      ${highlightRect.left}px ${highlightRect.top}px, 
      ${highlightRect.right}px ${highlightRect.top}px, 
      ${highlightRect.right}px ${highlightRect.bottom}px, 
      ${highlightRect.left}px ${highlightRect.bottom}px, 
      ${highlightRect.left}px 100%, 100% 100%, 100% 0%
    )`
  } : {};

  // 툴팁 위치 계산
  const getTooltipStyle = (): React.CSSProperties => {
    if (!highlightRect) return { top: '50%', left: '50%', transform: 'translate(-50%, -50%)' };

    const padding = 20;
    if (step.position === 'right') {
      return { top: highlightRect.top, left: highlightRect.right + padding };
    }
    if (step.position === 'bottom') {
      return { top: highlightRect.bottom + padding, left: highlightRect.left };
    }
    return { top: highlightRect.top, left: highlightRect.left };
  };

  return (
    <div className="fixed inset-0 z-[300] pointer-events-none">
      {/* Dimmed Background with Spotlight */}
      <div 
        className="absolute inset-0 bg-slate-900/60 backdrop-blur-[2px] transition-all duration-500 pointer-events-auto"
        style={overlayStyle}
      />

      {/* Tooltip Content */}
      <div 
        className="absolute w-80 bg-white rounded-2xl shadow-2xl p-6 pointer-events-auto transition-all duration-500 animate-in fade-in zoom-in-95"
        style={getTooltipStyle()}
      >
        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 text-[10px] font-bold rounded uppercase tracking-wider">Step {currentStep + 1} of {steps.length}</span>
            <button onClick={onComplete} className="text-slate-400 hover:text-slate-600">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>
          <div className="space-y-1">
            <h3 className="text-base font-bold text-slate-900">{step.title}</h3>
            <p className="text-xs text-slate-500 leading-relaxed">{step.description}</p>
          </div>
          <div className="flex items-center space-x-2 pt-2">
            <button 
              onClick={handleNext}
              className="flex-1 py-2.5 bg-slate-900 text-white rounded-xl text-xs font-bold hover:bg-slate-800 transition-all active:scale-95"
            >
              {currentStep === steps.length - 1 ? "시작하기" : "다음 단계로"}
            </button>
          </div>
        </div>

        {/* Triangle arrow for tooltip */}
        {highlightRect && step.position === 'right' && (
          <div className="absolute left-0 top-6 -translate-x-full w-0 h-0 border-y-[8px] border-y-transparent border-r-[8px] border-r-white" />
        )}
        {highlightRect && step.position === 'bottom' && (
          <div className="absolute top-0 left-6 -translate-y-full w-0 h-0 border-x-[8px] border-x-transparent border-b-[8px] border-b-white" />
        )}
      </div>
    </div>
  );
};

