import { PageType } from './types';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<PageType>('dashboard');
  const [toasts, setToasts] = useState<{id: string, message: string, type: ToastType}[]>([]);
  const [showOnboarding, setShowOnboarding] = useState(false);

  useEffect(() => {
    const hasVisited = localStorage.getItem('ff_visited_v2');
    if (!hasVisited) {
      setShowOnboarding(true);
    }
  }, []);

  const startOnboarding = () => {
    setShowOnboarding(true);
  };

  const completeOnboarding = () => {
    localStorage.setItem('ff_visited_v2', 'true');
    setShowOnboarding(false);
  };

  const removeToast = useCallback((id: string) => {
    setToasts(prev => prev.filter(t => t.id !== id));
  }, []);

  const showToast = useCallback((message: string, type: ToastType = 'success') => {
    const id = Math.random().toString(36).substring(2, 9);
    setToasts(prev => [...prev, { id, message, type }]);
    setTimeout(() => {
      removeToast(id);
    }, 5000); // 닫기 버튼이 생겼으므로 노출 시간을 소폭 늘림
  }, [removeToast]);

  const handlePageChange = useCallback((page: PageType) => {
    if (page === currentPage) return;
    setCurrentPage(page);

    const mainContent = document.getElementById('main-scroll-view');
    if (mainContent) mainContent.scrollTop = 0;
  }, [currentPage]);

  const renderContent = () => {
    switch (currentPage) {
      case 'dashboard': return <Dashboard />;
      case 'chat-manage': return <UserManagement onNotify={showToast} />;
      case 'ai-basic': return <AIBasicSettings onNotify={showToast} />;
      case 'test-toast': return <ToastTest onNotify={showToast} />;
      default: return <PlaceholderView title="준비 중" description="상세 기능을 구현 중입니다." />;
    }
  };

  return (
    <div className="flex h-screen w-full bg-[#f8fafc] overflow-hidden antialiased text-slate-900">
      {showOnboarding && <Onboarding onComplete={completeOnboarding} onNavigate={handlePageChange} />}

      <Sidebar 
        currentPage={currentPage} 
        onNavigate={handlePageChange} 
        onRestartGuide={startOnboarding}
      />

      <div className="flex flex-col flex-1 min-w-0 bg-white shadow-[-4px_0_24px_rgba(0,0,0,0.01)] relative">
        <Header currentPage={currentPage} />

        <main 
          id="main-scroll-view" 
          className="flex-1 overflow-y-auto relative bg-[#f8fafc] custom-scrollbar"
        >
          <div 
            className={`max-w-7xl mx-auto p-8 ${currentPage === 'dashboard' ? 'animate-in fade-in duration-700' : ''}`}
          >
            {renderContent()}
          </div>
        </main>
      </div>

      <div className="fixed bottom-6 right-6 z-[300] flex flex-col gap-3 pointer-events-none">
        {toasts.map(toast => (
          <div key={toast.id} className="pointer-events-auto">
            <Toast 
              message={toast.message} 
              type={toast.type} 
              onClose={() => removeToast(toast.id)} 
            />
          </div>
        ))}
      </div>
    </div>
  );
};

export default App;

import React from 'react';

export type ToastType = 'success' | 'error' | 'info';

interface ToastProps {
  message: string;
  type: ToastType;
  onClose?: () => void;
}

export const Toast: React.FC<ToastProps> = ({ message, type, onClose }) => {
  const getIcon = () => {
    switch (type) {
      case 'success':
        return (
          <div className="w-4 h-4 bg-emerald-500 rounded-full flex items-center justify-center text-white mr-3">
            <svg className="w-2.5 h-2.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M5 13l4 4L19 7" />
            </svg>
          </div>
        );
      case 'error':
        return (
          <div className="w-4 h-4 bg-rose-500 rounded-full flex items-center justify-center text-white mr-3">
            <svg className="w-2.5 h-2.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </div>
        );
      case 'info':
        return (
          <div className="w-4 h-4 bg-indigo-500 rounded-full flex items-center justify-center text-white mr-3">
            <svg className="w-2.5 h-2.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
            </svg>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className={`
      flex items-center bg-slate-900/95 backdrop-blur-md text-white pl-4 pr-3 py-3 rounded-2xl 
      shadow-2xl border border-white/10
      animate-in fade-in slide-in-from-right-4 duration-300 pointer-events-auto
      max-w-xs group relative
    `}>
      {getIcon()}
      <span className="text-[12px] font-bold tracking-tight pr-6">{message}</span>

      {onClose && (
        <button 
          onClick={onClose}
          className="ml-auto w-5 h-5 flex items-center justify-center rounded-lg hover:bg-white/10 text-white/40 hover:text-white transition-colors"
        >
          <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" />
          </svg>
        </button>
      )}
    </div>
  );
};

