export const Onboarding: React.FC<OnboardingProps> = ({ onComplete, onNavigate, onStepAction }) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [highlightRect, setHighlightRect] = useState<DOMRect | null>(null);

  useEffect(() => {
    const step = steps[currentStep];
    if (step.page) {
      onNavigate(step.page);
    }

    // 패널 애니메이션 시간을 고려하여 6/7 단계(index 5)에서는 대기 시간을 더 길게 가짐
    const delay = currentStep === 5 ? 600 : 150;

    const timer = setTimeout(() => {
      if (step.selector) {
        const el = document.querySelector(step.selector);
        if (el) {
          setHighlightRect(el.getBoundingClientRect());
        }
      } else {
        setHighlightRect(null);
      }
    }, delay);

    return () => clearTimeout(timer);
  }, [currentStep, onNavigate]);

  const handleNext = () => {
    // 5단계(인덱스 4)에서 다음 클릭 시 Alex Johnson 클릭 트리거
    if (currentStep === 4) {
      onStepAction?.(4);
    }

    if (currentStep < steps.length - 1) {
      setCurrentStep(currentStep + 1);
    } else {
      onComplete(true);
    }
  };

  const step = steps[currentStep];

  const overlayStyle: React.CSSProperties = highlightRect ? {
    clipPath: `polygon(
      0% 0%, 0% 100%, 
      ${highlightRect.left}px 100%, 
      ${highlightRect.left}px ${highlightRect.top}px, 
      ${highlightRect.right}px ${highlightRect.top}px, 
      ${highlightRect.right}px ${highlightRect.bottom}px, 
      ${highlightRect.left}px ${highlightRect.bottom}px, 
      ${highlightRect.left}px 100%, 100% 100%, 100% 0%
    )`
  } : {};

  const getTooltipStyle = (): React.CSSProperties => {
    if (!highlightRect) return { top: '50%', left: '50%', transform: 'translate(-50%, -50%)' };

    const padding = 24;
    switch (step.position) {
      case 'right': return { top: highlightRect.top, left: highlightRect.right + padding };
      case 'bottom': return { top: highlightRect.bottom + padding, left: highlightRect.left };
      case 'left': return { top: highlightRect.top, left: highlightRect.left - 320 - padding };
      case 'top': return { top: highlightRect.top - 180 - padding, left: highlightRect.left - 100 };
      default: return { top: '50%', left: '50%', transform: 'translate(-50%, -50%)' };
    }
  };

  return (
    <div className="fixed inset-0 z-[1000] pointer-events-none">
      <div 
        className="absolute inset-0 bg-slate-900/40 backdrop-blur-[1px] transition-all duration-500 pointer-events-auto"
        style={overlayStyle}
      />

      <div 
        className="absolute w-80 bg-white rounded-3xl shadow-2xl p-6 pointer-events-auto transition-all duration-500 animate-in fade-in zoom-in-95"
        style={getTooltipStyle()}
      >
        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 text-[9px] font-black rounded uppercase tracking-widest">Update {currentStep + 1}/{steps.length}</span>
            <button onClick={() => onComplete(false)} className="text-slate-400 hover:text-slate-600 transition-colors">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>
          <div className="space-y-1.5">
            <h3 className="text-[15px] font-bold text-slate-900 leading-tight">{step.title}</h3>
            <p className="text-[12px] text-slate-500 leading-relaxed font-medium">{step.description}</p>
          </div>
          <div className="flex items-center space-x-2 pt-2">
            <button 
              onClick={handleNext}
              className="flex-1 py-3 bg-indigo-600 text-white rounded-xl text-xs font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-600/20"
            >
              {currentStep === steps.length - 1 ? "시작하기" : "다음 기능"}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useCallback, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { Header } from './components/Header';
import { Dashboard } from './components/Dashboard';
import { UserManagement } from './components/UserManagement';
import { AIBasicSettings } from './components/AIBasicSettings';
import { PlaceholderView } from './components/PlaceholderView';
import { Toast, ToastType } from './components/Toast';
import { ToastTest } from './components/ToastTest';
import { Onboarding } from './components/Onboarding';
import { PageType } from './types';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<PageType>('dashboard');
  const [toasts, setToasts] = useState<{id: string, message: string, type: ToastType}[]>([]);
  const [showOnboarding, setShowOnboarding] = useState(false);
  const [triggerSaveAction, setTriggerSaveAction] = useState(false);
  const [triggerSelectAction, setTriggerSelectAction] = useState(false);

  useEffect(() => {
    const hasVisited = localStorage.getItem('ff_visited_v2');
    if (!hasVisited) {
      setShowOnboarding(true);
    }
  }, []);

  const startOnboarding = () => {
    setShowOnboarding(true);
  };

  const completeOnboarding = (isFinalAction?: boolean) => {
    localStorage.setItem('ff_visited_v2', 'true');
    setShowOnboarding(false);
    if (isFinalAction) {
      setTriggerSaveAction(true);
    }
  };

  const handleStepAction = (stepIndex: number) => {
    if (stepIndex === 4) {
      // 5단계에서 다음으로 넘어갈 때 상세 패널 노출 트리거
      setTriggerSelectAction(true);
    }
  };

  const removeToast = useCallback((id: string) => {
    setToasts(prev => prev.filter(t => t.id !== id));
  }, []);

  const showToast = useCallback((message: string, type: ToastType = 'success') => {
    const id = Math.random().toString(36).substring(2, 9);
    setToasts(prev => [...prev, { id, message, type }]);
    setTimeout(() => {
      removeToast(id);
    }, 5000);
  }, [removeToast]);

  const handlePageChange = useCallback((page: PageType) => {
    if (page === currentPage) return;
    setCurrentPage(page);

    const mainContent = document.getElementById('main-scroll-view');
    if (mainContent) mainContent.scrollTop = 0;
  }, [currentPage]);

  const renderContent = () => {
    switch (currentPage) {
      case 'dashboard': return <Dashboard />;
      case 'chat-manage': 
        return (
          <UserManagement 
            onNotify={showToast} 
            forceSaveTrigger={triggerSaveAction}
            forceSelectTrigger={triggerSelectAction}
            onActionHandled={() => {
              setTriggerSaveAction(false);
              setTriggerSelectAction(false);
            }}
          />
        );
      case 'ai-basic': return <AIBasicSettings onNotify={showToast} />;
      case 'test-toast': return <ToastTest onNotify={showToast} />;
      default: return <PlaceholderView title="준비 중" description="상세 기능을 구현 중입니다." />;
    }
  };

  return (
    <div className="flex h-screen w-full bg-[#f8fafc] overflow-hidden antialiased text-slate-900">
      {showOnboarding && (
        <Onboarding 
          onComplete={completeOnboarding} 
          onNavigate={handlePageChange} 
          onStepAction={handleStepAction}
        />
      )}

      <Sidebar 
        currentPage={currentPage} 
        onNavigate={handlePageChange} 
        onRestartGuide={startOnboarding}
      />

      <div className="flex flex-col flex-1 min-w-0 bg-white shadow-[-4px_0_24px_rgba(0,0,0,0.01)] relative">
        <Header currentPage={currentPage} />

        <main 
          id="main-scroll-view" 
          className="flex-1 overflow-y-auto relative bg-[#f8fafc] custom-scrollbar"
        >
          <div className="max-w-7xl mx-auto p-8">
            {renderContent()}
          </div>
        </main>
      </div>

      <div className="fixed bottom-6 right-6 z-[300] flex flex-col gap-3 pointer-events-none">
        {toasts.map(toast => (
          <div key={toast.id} className="pointer-events-auto">
            <Toast 
              message={toast.message} 
              type={toast.type} 
              onClose={() => removeToast(toast.id)} 
            />
          </div>
        ))}
      </div>
    </div>
  );
};

export default App;

