export const Onboarding: React.FC<OnboardingProps> = ({ onComplete, onNavigate, onStepAction }) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [highlightRect, setHighlightRect] = useState<DOMRect | null>(null);
  const observerRef = useRef<MutationObserver | null>(null);
  const animationFrameRef = useRef<number | null>(null);

  const updateHighlight = () => {
    const step = steps[currentStep];
    if (step.selector) {
      const el = document.querySelector(step.selector);
      if (el) {
        const rect = el.getBoundingClientRect();

        // 6/7 단계(index 5) 패널 노출 시점 정밀 체크: 패널이 화면 밖(오른쪽)에 있으면 아직 준비 안 됨
        if (currentStep === 5 && rect.left >= window.innerWidth - 10) {
          return false; 
        }

        setHighlightRect(rect);
        return true;
      }
    } else {
      setHighlightRect(null);
      return true;
    }
    return false;
  };

  useEffect(() => {
    const step = steps[currentStep];
    if (step.page) {
      onNavigate(step.page);
    }

    // MutationObserver와 requestAnimationFrame을 병행하여 
    // 레이아웃이 확정되는 즉시 하이라이트를 잡음 (불필요한 setTimeout 제거)
    const check = () => {
      if (!updateHighlight()) {
        animationFrameRef.current = requestAnimationFrame(check);
      }
    };

    if (!updateHighlight()) {
      if (observerRef.current) observerRef.current.disconnect();
      observerRef.current = new MutationObserver(updateHighlight);
      observerRef.current.observe(document.body, { childList: true, subtree: true, attributes: true });

      check(); // 루프 시작
    }

    return () => {
      observerRef.current?.disconnect();
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [currentStep, onNavigate]);

  // 실제 UI의 '업데이트 저장' 버튼 클릭 시 온보딩 즉시 종료 (7/7 단계)
  useEffect(() => {
    if (currentStep === 6) {
      const handleGlobalClick = (e: MouseEvent) => {
        const target = e.target as HTMLElement;
        if (target.closest('[data-tour="panel-save-btn"]')) {
          onComplete(false);
        }
      };
      document.addEventListener('click', handleGlobalClick, true); // 캡처링 단계에서 가로채기
      return () => document.removeEventListener('click', handleGlobalClick, true);
    }
  }, [currentStep, onComplete]);

  const handleNext = () => {
    if (currentStep === 4) {
      onStepAction?.(4); // 패널 열기 트리거
    }

    if (currentStep < steps.length - 1) {
      setCurrentStep(currentStep + 1);
    } else {
      onComplete(true);
    }
  };

  const step = steps[currentStep];

  const overlayStyle: React.CSSProperties = highlightRect ? {
    clipPath: `polygon(
      0% 0%, 0% 100%, 
      ${highlightRect.left}px 100%, 
      ${highlightRect.left}px ${highlightRect.top}px, 
      ${highlightRect.right}px ${highlightRect.top}px, 
      ${highlightRect.right}px ${highlightRect.bottom}px, 
      ${highlightRect.left}px ${highlightRect.bottom}px, 
      ${highlightRect.left}px 100%, 100% 100%, 100% 0%
    )`
  } : {};

  const getTooltipStyle = (): React.CSSProperties => {
    if (!highlightRect) return { top: '50%', left: '50%', transform: 'translate(-50%, -50%)' };

    const padding = 24;
    switch (step.position) {
      case 'right': return { top: highlightRect.top, left: highlightRect.right + padding };
      case 'bottom': return { top: highlightRect.bottom + padding, left: highlightRect.left };
      case 'left': 
        // 7/7 단계(index 6) 카드를 저장 버튼보다 높게 배치
        const transform = currentStep === 6 ? 'translateY(-100%)' : undefined;
        const top = currentStep === 6 ? highlightRect.top - padding : highlightRect.top;
        return { top, left: highlightRect.left - 320 - padding, transform };
      case 'top': return { top: highlightRect.top - 180 - padding, left: highlightRect.left - 100 };
      default: return { top: '50%', left: '50%', transform: 'translate(-50%, -50%)' };
    }
  };

  return (
    <div className="fixed inset-0 z-[1000] pointer-events-none">
      {/* 
        transition-all 제거: 움직임 없이 즉시 스냅 
      */}
      <div 
        className="absolute inset-0 bg-slate-900/40 backdrop-blur-[1px] pointer-events-auto"
        style={overlayStyle}
      />

      {/* 
        애니메이션 클래스 제거: 카드와 하이라이트가 번쩍이거나 이동하는 현상 방지 
      */}
      <div 
        className="absolute w-80 bg-white rounded-3xl shadow-2xl p-6 pointer-events-auto"
        style={getTooltipStyle()}
      >
        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 text-[9px] font-black rounded uppercase tracking-widest">Update {currentStep + 1}/{steps.length}</span>
            <button onClick={() => onComplete(false)} className="text-slate-400 hover:text-slate-600 transition-colors">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>
          <div className="space-y-1.5">
            <h3 className="text-[15px] font-bold text-slate-900 leading-tight">{step.title}</h3>
            <p className="text-[12px] text-slate-500 leading-relaxed font-medium">{step.description}</p>
          </div>
          <div className="flex items-center space-x-2 pt-2">
            <button 
              onClick={handleNext}
              className="flex-1 py-3 bg-indigo-600 text-white rounded-xl text-xs font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-600/20"
            >
              {currentStep === steps.length - 1 ? "시작하기" : "다음 기능"}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

