const CountUp: React.FC<{ value: string; duration?: number; suffix?: string }> = ({ value, duration = 1500, suffix = "" }) => {
  const [displayValue, setDisplayValue] = useState(0);
  const numericValue = parseFloat(value.replace(/,/g, ''));
  const isK = value.includes('k');
  const isPercent = value.includes('%');
  const isMs = value.includes('ms');

  useEffect(() => {
    let start = 0;
    const end = numericValue;
    const range = end - start;
    let startTime: number | null = null;

    const step = (timestamp: number) => {
      if (!startTime) startTime = timestamp;
      const progress = Math.min((timestamp - startTime) / duration, 1);
      const easeOutQuad = (t: number) => t * (2 - t);
      const current = easeOutQuad(progress) * range + start;

      setDisplayValue(current);

      if (progress < 1) {
        window.requestAnimationFrame(step);
      }
    };

    window.requestAnimationFrame(step);
  }, [value, duration]);

  const formatted = isK 
    ? displayValue.toFixed(1) + 'k' 
    : isPercent 
      ? displayValue.toFixed(1) + '%' 
      : isMs
        ? Math.floor(displayValue) + 'ms'
        : Math.floor(displayValue).toLocaleString();

  return <span>{formatted}</span>;
};

