const CountUp: React.FC<{ value: string; duration?: number }> = ({ value, duration = 1500 }) => {
  const [displayValue, setDisplayValue] = useState(0);
  const numericValue = parseFloat(value.replace(/,/g, ''));
  const isK = value.includes('k');
  const isPercent = value.includes('%');
  const isMs = value.includes('ms');

  useEffect(() => {
    let startTime: number | null = null;
    const step = (timestamp: number) => {
      if (!startTime) startTime = timestamp;
      const progress = Math.min((timestamp - startTime) / duration, 1);
      const easeOutQuad = (t: number) => t * (2 - t);
      setDisplayValue(easeOutQuad(progress) * numericValue);
      if (progress < 1) window.requestAnimationFrame(step);
    };
    window.requestAnimationFrame(step);
  }, [value, duration, numericValue]);

  if (isK) return <span>{displayValue.toFixed(1)}k</span>;
  if (isPercent) return <span>{displayValue.toFixed(1)}%</span>;
  if (isMs) return <span>{Math.floor(displayValue)}ms</span>;
  return <span>{Math.floor(displayValue).toLocaleString()}</span>;
};

